import {
  collection,
  addDoc,
  updateDoc,
  deleteDoc,
  doc,
  onSnapshot,
  orderBy,
  query,
  getDoc,
  getDocs,
  runTransaction,
  serverTimestamp,
} from "firebase/firestore"
import { db } from "./firebase"

export type RankingData = {
  name: string
  location: string
  ranking: number
  lat?: number
  lng?: number
  colour?: string
  updatedAt?: any
}

export type Ranking = RankingData & {
  id: string
}

/**
 * Subscribe to user's rankings (live updates)
 */
export function subscribeMyRankings(
  uid: string,
  callback: (rankings: Ranking[]) => void
) {
  const q = query(
    collection(db, "users", uid, "rankings"),
    orderBy("ranking", "asc")
  )
  return onSnapshot(q, (snap) => {
    callback(snap.docs.map((d) => ({ id: d.id, ...d.data() } as Ranking)))
  })
}

/**
 * Add a new ranking
 */
export async function addRanking(uid: string, data: RankingData) {
  await addDoc(collection(db, "users", uid, "rankings"), {
    ...data,
    updatedAt: serverTimestamp(),
  })
}

/**
 * Update an existing ranking
 */
export async function updateRanking(
  uid: string,
  rankingId: string,
  patch: Partial<RankingData>
) {
  await updateDoc(doc(db, "users", uid, "rankings", rankingId), {
    ...patch,
    updatedAt: serverTimestamp(),
  })
}

/**
 * Delete a ranking
 */
export async function deleteRanking(uid: string, rankingId: string) {
  await deleteDoc(doc(db, "users", uid, "rankings", rankingId))
}

/**
 * Claim a username (transactional operation)
 */
export async function claimUsername(uid: string, usernameRaw: string) {
  const username = usernameRaw.trim().toLowerCase()
  if (!/^[a-z0-9_]{3,20}$/.test(username)) {
    throw new Error("Username must be 3-20 chars: a-z, 0-9, underscore.")
  }

  const unameRef = doc(db, "usernames", username)
  const userRef = doc(db, "users", uid)

  await runTransaction(db, async (tx) => {
    const existing = await tx.get(unameRef)
    if (existing.exists()) throw new Error("Username already taken.")

    tx.set(unameRef, { uid, createdAt: serverTimestamp() })
    tx.set(userRef, { username, createdAt: serverTimestamp() }, { merge: true })
  })

  return username
}

/**
 * Get rankings by username (read-only)
 */
export async function getRankingsByUsername(usernameRaw: string) {
  const username = usernameRaw.trim().toLowerCase()
  const unameSnap = await getDoc(doc(db, "usernames", username))
  if (!unameSnap.exists()) throw new Error("User not found.")

  const uid = unameSnap.data().uid as string
  const q = query(
    collection(db, "users", uid, "rankings"),
    orderBy("ranking", "asc")
  )
  const rankingsSnap = await getDocs(q)
  return rankingsSnap.docs.map((d) => ({ id: d.id, ...d.data() } as Ranking))
}

/**
 * Get global top 10 leaderboard (from global doc - Cloud Function populated)
 */
export async function getGlobalTop10() {
  const snap = await getDoc(doc(db, "global", "leaderboards"))
  return snap.exists() ? (snap.data().top10 || []) : []
}

export type AggregatedSpot = {
  name: string
  location: string
  count: number
  sumOfRankings: number
  averageRanking: number
  lat?: number
  lng?: number
}

/**
 * Get aggregated top 10 from all users' rankings
 * Ranks by frequency (count), then by average ranking (lower is better)
 * Reads from /users collection with sub-collections instead of collectionGroup
 */
export async function getAggregatedTop10(): Promise<AggregatedSpot[]> {
  // Get all users
  const usersSnap = await getDocs(collection(db, "users"))
  
  // Aggregate: count occurrences and sum rankings for each spot (by name + location)
  const spots = new Map<string, { name: string; location: string; count: number; sumOfRankings: number; lat?: number; lng?: number }>()
  
  // Read rankings from each user
  for (const userDoc of usersSnap.docs) {
    const rankingsSnap = await getDocs(collection(db, "users", userDoc.id, "rankings"))
    
    rankingsSnap.docs.forEach((d) => {
      const data = d.data()
      const name = (data.name || "").trim()
      const location = (data.location || "").trim()
      const ranking = typeof data.ranking === "number" ? data.ranking : 999
      
      if (!name || !location) return
      const key = `${name.toLowerCase()}|${location.toLowerCase()}`
      const existing = spots.get(key)
      
      if (existing) {
        existing.count++
        existing.sumOfRankings += ranking
        if (data.lat != null && data.lng != null && existing.lat == null) {
          existing.lat = data.lat
          existing.lng = data.lng
        }
      } else {
        spots.set(key, {
          name,
          location,
          count: 1,
          sumOfRankings: ranking,
          lat: data.lat,
          lng: data.lng,
        })
      }
    })
  }

  // Convert to array with average ranking calculated
  const aggregated = Array.from(spots.values()).map(spot => ({
    ...spot,
    averageRanking: spot.sumOfRankings / spot.count,
  }))

  // Sort by count (desc) first, then by average ranking (asc), take top 10
  return aggregated
    .sort((a, b) => {
      // Primary: sort by frequency (count) descending
      if (b.count !== a.count) {
        return b.count - a.count
      }
      // Secondary: sort by average ranking ascending (lower average is better)
      return a.averageRanking - b.averageRanking
    })
    .slice(0, 10)
}
