"use client"

import { useState, useEffect } from "react"
import { getAggregatedTop10, type AggregatedSpot } from "@/lib/firebase-rankings"
import { Loader2 } from "lucide-react"

interface GlobalLeaderboardProps {
  selectedSpot: number | null
  onSpotClick: (spotRank: number) => void
}

export function GlobalLeaderboard({ selectedSpot, onSpotClick }: GlobalLeaderboardProps) {
  const [topSpots, setTopSpots] = useState<AggregatedSpot[] | null>(null)
  const [loading, setLoading] = useState(true)
  const [useAggregated, setUseAggregated] = useState(true)

  useEffect(() => {
    let cancelled = false
    async function load() {
      setLoading(true)
      try {
        const aggregated = await getAggregatedTop10()
        if (!cancelled) {
          setTopSpots(aggregated)
          setUseAggregated(aggregated.length > 0)
        }
      } catch (e) {
        if (!cancelled) {
          setUseAggregated(false)
          setTopSpots([])
        }
      } finally {
        if (!cancelled) setLoading(false)
      }
    }
    load()
    return () => { cancelled = true }
  }, [])

  // Use aggregated data from all users
  const spots = topSpots && topSpots.length > 0
    ? topSpots.map((s, i) => ({
        rank: i + 1,
        name: s.name,
        location: s.location,
        count: s.count,
      }))
    : []

  return (
    <div className="flex flex-col h-full">
      {/* Leaderboard List */}
      <div className="flex-1 overflow-y-auto">
        {loading ? (
          <div className="flex items-center justify-center p-8">
            <Loader2 className="size-6 animate-spin text-muted-foreground" />
          </div>
        ) : (
          <div className="space-y-2 p-3">
            {topSpots && topSpots.length > 0 && (
              <p className="text-xs text-muted-foreground pb-2">
                Community top 10 · most ranked spots
              </p>
            )}
            {spots.map((spot, index) => {
              const rank = "rank" in spot ? spot.rank : index + 1
              const isSelected = selectedSpot === rank
              return (
                <button
                  key={`${spot.name}-${spot.location}-${index}`}
                  onClick={() => onSpotClick(rank)}
                  className={`w-full text-left p-3 rounded-lg transition-all duration-200 ${
                    isSelected
                      ? "bg-primary/20 border border-primary"
                      : "bg-accent/30 border border-border hover:bg-accent/50"
                  }`}
                >
                  <div className="flex items-start gap-3">
                    <div className="flex-shrink-0">
                      <div className="flex h-8 w-8 items-center justify-center rounded-full bg-primary/30 text-xs font-bold text-primary">
                        {rank}
                      </div>
                    </div>
                    <div className="flex-1 min-w-0">
                      <p className="font-semibold text-foreground text-sm truncate">
                        {spot.name}
                      </p>
                      <p className="text-xs text-muted-foreground truncate">
                        {spot.location}
                      </p>
                      {"count" in spot && (
                        <div className="flex flex-col gap-1 mt-1">
                          <div className="flex items-center gap-2">
                            <span className="text-xs text-muted-foreground">
                              {spot.count} user{(spot as { count: number }).count > 1 ? "s" : ""} ranked
                            </span>
                            {("averageRanking" in spot) && (
                              <span className="text-xs text-muted-foreground">
                                • avg rank: {((spot as any).averageRanking).toFixed(1)}
                              </span>
                            )}
                          </div>
                        </div>
                      )}
                      {"rating" in spot && (
                        <div className="flex items-center gap-2 mt-1">
                          <span className="text-xs font-medium text-muted-foreground">
                            {(spot as { rating: number }).rating} ★
                          </span>
                          <span className="text-xs text-muted-foreground italic">
                            {(spot as { vibe: string }).vibe}
                          </span>
                        </div>
                      )}
                    </div>
                  </div>
                </button>
              )
            })}
          </div>
        )}
      </div>
    </div>
  )
}

